The idea is to keep the count for "A" and  "AB" for the prefixes of all strings that can be made from T.
The memory can be reduced to O(1) as you can keep only the values for the current prefix.
```
const int mod = 1e9 + 7;
int solve(const string& s)
{
	long long cnt[2] = {0}, ans = 0, pw = 1;

	for(int i = 0;i < s.size();++i)
	{
		if(s[i] == 'A')
			cnt[0] += pw, cnt[0] %= mod;
		else if(s[i] == 'B')
			cnt[1] += cnt[0], cnt[1] %= mod;
		else if(s[i] == 'C')
			ans += cnt[1], ans %= mod;
		else if(s[i] == '?')
		{
			ans = cnt[1] + 3LL * ans, ans %= mod;
			cnt[1] = cnt[0] + 3LL * cnt[1], cnt[1] %= mod;
			cnt[0] = pw + 3LL * cnt[0], cnt[0] %= mod;
			pw *= 3;
			pw %= mod;
		}
	}
	return ans;
}

