#include<bits/stdc++.h>
using namespace std;
long long int getPow(long long int m,long long int n,long long int MOD){
    if(n == 0){
        return 1;
    }
    long long int ans = getPow(m,n/2,MOD)%MOD;
    ans = (ans * ans)%MOD;
    if(n%2){
        ans = (ans * m)%MOD;
    }
    return ans%MOD;
}
int main() {
    int n ;
    cin >> n;
    string s;
    cin >> s;
    vector<vector<long long int>> dp(n+1,vector<long long int>(4));
    long long int MOD = 1e9 + 7;
    for(int i = 0;i <= n;i++){
        dp[i][0] = 1;
    }
    int cnt = 0;
    for(int i = 1;i <= n;i++){
        dp[i] = dp[i-1];
        if(s[i-1] == 'A'){
            dp[i][1] = dp[i-1][1] + getPow(3,cnt,MOD);
        }
        if(s[i-1] == 'B'){
            dp[i][2] = dp[i-1][2] + dp[i-1][1];
        }
        if(s[i-1] == 'C'){
            dp[i][3] = dp[i-1][3] + dp[i-1][2];
        }
        if(s[i-1] == '?'){
            dp[i][1] = ((3*dp[i-1][1])%MOD + (long long int)getPow(3,cnt,MOD)%MOD)%MOD;
            dp[i][2] = ((3*dp[i-1][2])%MOD + dp[i-1][1]%MOD)%MOD;
            dp[i][3] = ((3*dp[i-1][3])%MOD + dp[i-1][2]%MOD)%MOD;
            cnt++;
        }
        dp[i][1] %= MOD;
        dp[i][2] %= MOD;
        dp[i][3] %= MOD;
    }

    cout << dp[n][3] << endl;
    return 0;
}
